// SPDX-License-Identifier: MIT
// solhint-disable
pragma solidity ^0.8.21;

import {AMerkleWhitelisted} from "../../access/AMerkleWhitelisted.sol";

contract MerkleWhitelistedMock is AMerkleWhitelisted {
    event WhitelistedUser();
    event WhitelistedData();

    function onlyWhitelistedMethod(
        uint256 amount_,
        bytes32[] calldata merkleProof_
    ) external onlyWhitelisted(_encode(amount_), merkleProof_) {
        emit WhitelistedData();
    }

    function onlyWhitelistedUserMethod(
        bytes32[] calldata merkleProof_
    ) external onlyWhitelistedUser(msg.sender, merkleProof_) {
        emit WhitelistedUser();
    }

    function isWhitelisted(
        bytes32 leaf_,
        bytes32[] memory merkleProof_
    ) internal view returns (bool) {
        return _isWhitelisted(leaf_, merkleProof_);
    }

    function isWhitelistedUser(
        address user_,
        bytes32[] memory merkleProof_
    ) internal view returns (bool) {
        return _isWhitelistedUser(user_, merkleProof_);
    }

    function setMerkleRoot(bytes32 merkleRoot_) external {
        _setMerkleRoot(merkleRoot_);
    }

    function _encode(uint256 amount_) private view returns (bytes memory) {
        return abi.encodePacked(amount_, msg.sender);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.21;

import {ARecoverableAccount} from "../../account-abstraction/ARecoverableAccount.sol";

contract RecoverableAccountMock is ARecoverableAccount {
    function initialize(address entryPoint_, address trustedExecutor_) external initializer {
        __ARecoverableAccount_init(entryPoint_, trustedExecutor_);
    }

    function callInitialize(address entryPoint_, address trustedExecutor_) external {
        __ARecoverableAccount_init(entryPoint_, trustedExecutor_);
    }

    function updateTrustedExecutor(address newTrustedExecutor_) external {
        _updateTrustedExecutor(newTrustedExecutor_);
    }
}

contract RecoverableAccountMockWithHooks is RecoverableAccountMock {
    event BeforeCall(address to_, uint256 value_, bytes data_);
    event AfterCall(address to_, uint256 value_, bytes data_);

    function _beforeCall(address to_, uint256 value_, bytes memory data_) internal override {
        emit BeforeCall(to_, value_, data_);
    }

    function _afterCall(address to_, uint256 value_, bytes memory data_) internal override {
        emit AfterCall(to_, value_, data_);
    }
}

contract Caller {
    function callAddRecoveryProvider(
        address payable account_,
        address provider_,
        bytes memory recoveryData_
    ) external {
        ARecoverableAccount(account_).addRecoveryProvider(provider_, recoveryData_);
    }
}

